-func pickByUpdatedAt(left, right string, leftTime, rightTime time.Time) string {
-	if left == right {
-		return left
-	}
-	if isTimeAfter(leftTime, rightTime) {
-		return left
-	}
-	return right
-}
-
-func pickStatusByUpdatedAt(left, right types.Status, leftTime, rightTime time.Time) types.Status {
-	if left == right {
-		return left
-	}
-	if isTimeAfter(leftTime, rightTime) {
-		return left
-	}
-	return right
-}
