-			}
-		}
-		if !inRight && inLeft {
-			if fallback, found := rightByID[leftIssue.ID]; found {
-				rightIssue = fallback
-				inRight = true
-				// Mark the fallback's key as processed to avoid duplicate
-				processed[makeKey(fallback)] = true
-			}
-		}
